let catalogVersion = 0;

const baseProducts = [
  { id: 1, name: 'Laptop', price: 1299, inStock: true },
  { id: 2, name: 'Phone', price: 799, inStock: true },
  { id: 3, name: 'Tablet', price: 499, inStock: false },
  { id: 4, name: 'Headphones', price: 199, inStock: true },
  { id: 5, name: 'Smartwatch', price: 349, inStock: true },
  { id: 6, name: 'Keyboard', price: 89, inStock: false },
  { id: 7, name: 'Mouse', price: 49, inStock: true },
  { id: 8, name: 'Monitor', price: 449, inStock: true },
];

/**
 * Simulates price and availability updates from an upstream ERP/PIM system.
 * Each call reflects the latest imported data based on `catalogVersion`.
 */
function getCurrentCatalog() {
  return baseProducts.map((product) => {
    // Versions 0, 1, 2, … — each sync moves to the next tier
    const tier = catalogVersion % 5;
    const multipliers = [1.0, 0.95, 0.9, 0.85, 0.8];
    const adjustedPrice = Math.round(product.price * multipliers[tier]);

    // Flip some stock status to simulate inventory changes
    const stockRotations = [
      { 1: true, 3: false },
      { 3: true, 6: true },
      { 6: false, 4: false },
      { 4: true, 7: false },
      { 7: true, 2: false },
    ];

    return {
      ...product,
      price: adjustedPrice,
      inStock: stockRotations[tier]?.[product.id] ?? product.inStock,
      // Informational field so the UI can show when the data changed
      _syncedAt: new Date().toISOString(),
      _catalogVersion: catalogVersion,
    };
  });
}

export async function getAllProducts() {
  // Simulate database read latency
  await new Promise((resolve) => setTimeout(resolve, 80));

  return getCurrentCatalog();
}

/**
 * Simulates a long-running sync with an upstream ERP/PIM system.
 * In production this could process tens of thousands of SKUs,
 * update a database, publish to a message queue, etc.
 */
export async function syncCatalog() {
  // In production this would be a queue job — not something the HTTP
  // request blocks on for thousands of SKUs.
  await new Promise((resolve) => setTimeout(resolve, 2000));

  catalogVersion++;
}

