34	    return {
35	      ...product,
36	      price: adjustedPrice,
37	      inStock: stockRotations[tier]?.[product.id] ?? product.inStock,
38	      // Informational field so the UI can show when the data changed
39	      _syncedAt: new Date().toISOString(),
